sys_variable_value.value:
(function (outputs, steps, params, stepResult, assertEqual) {

	var bLog = false;

	var _gtReadComplex = new global.GlobalToolsRecordReadComplex();
	var _gtRecordWrite = new global.GlobalToolsRecordWrite();
	var _gtATF = new global.GlobalToolsATF('GlobalToolsRecordReadComplex', _gtReadComplex, bLog, outputs, steps, params, stepResult, assertEqual);

	// 1 basic value read of a single known record
	_gtATF.runATF('getData', /"user_name":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'] });

	// 2 total record count is reported
	_gtATF.runATF('getData', /"iNumberOfRecordsReturned":1/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'] });

	// 3 camel case field label
	_gtATF.runATF('getData', /"userName":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'], bUseFieldCamelCaseLabel: true });

	// 4 pascal case field label
	_gtATF.runATF('getData', /"UserName":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'], bUseFieldPascalCaseLabel: true });

	// 5 display field returns the display_value / value object form
	_gtATF.runATF('getData', /"user_name":\{"display_value"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aDisplayFields: ['user_name'] });

	// 6 allfields read includes the field
	_gtATF.runATF('getData', /"user_name":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['allfields'] });

	// 7 requested fields narrow an allfields config to the requested set
	_gtATF.runATF('getData', /"user_name":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['allfields'], aRequestedFields: ['user_name'] });

	// 8 reference field dot walk produces the concatenated key (company is core on sys_user)
	_gtATF.runATF('getData', /"company_name"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'], oReferenceFields: { company: { aFields: ['name'] } } });

	// 9 attachment info object is always added under the attachments key
	_gtATF.runATF('getData', /"attachments":\{/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'], bReturnAttachmentInfoObject: true });

	// 10 sReturnType first returns a single object instead of an array
	_gtATF.runATF('getData', /"data":\{"user_name":"admin"/, { sTable: 'sys_user', sQuery: 'user_name=admin', aFields: ['user_name'], sReturnType: 'first' });

	// 11 empty result sets the 204 no content status
	_gtATF.runATF('getData', /"iResponseStatusCode":204/, { sTable: 'sys_user', sQuery: 'user_name=zzz_no_such_user_xyz', aFields: ['user_name'] });

	// 12 bOnlyReturnOneRecord with more than one match raises 417
	_gtATF.runATF('getData', /"iResponseStatusCode":417/, { sTable: 'sys_user', sQuery: '', bOnlyReturnOneRecord: true });

	// 13 bErrorMaxReturnCount over the configured maximum raises 413
	_gtATF.runATF('getData', /"iResponseStatusCode":413/, { sTable: 'sys_user', sQuery: '', bErrorMaxReturnCount: true, iMaxReturnCount: 1 });

	// Generate test data	
	var sCompanyId = '10000000000000000000000000000001';
	var sManagerId = '20000000000000000000000000000001';
	var sEmployeeId = '20000000000000000000000000000002';
	var sRoleAId = '30000000000000000000000000000001';
	var sRoleBId = '30000000000000000000000000000002';
	var sHasRoleAId = '40000000000000000000000000000001';
	var sHasRoleBId = '40000000000000000000000000000002';
	var sIncidentId = '50000000000000000000000000000001';
	_gtATF.generateTestData({
		core_company: [
			{ sys_id: sCompanyId, name: 'GTRRC Test Company' }
		],
		sys_user_role: [
			{ sys_id: sRoleAId, name: 'gtrrc_test_role_a' },
			{ sys_id: sRoleBId, name: 'gtrrc_test_role_b' }
		],
		sys_user: [
			{ sys_id: sManagerId, user_name: 'gtrrc.manager', first_name: 'GTRRC', last_name: 'Manager', name: 'GTRRC Manager' },
			{ sys_id: sEmployeeId, user_name: 'gtrrc.employee', first_name: 'GTRRC', last_name: 'Employee', name: 'GTRRC Employee', manager: sManagerId, company: sCompanyId }
		],
		sys_user_has_role: [
			{ sys_id: sHasRoleAId, user: sEmployeeId, role: sRoleAId },
			{ sys_id: sHasRoleBId, user: sEmployeeId, role: sRoleBId }
		],
		incident: [
			{ sys_id: sIncidentId, short_description: 'GTRRC Test Incident' }
		]
	}, true); // create fixture, log errors

	_gtRecordWrite.doRecord({sys_id: sIncidentId, comments: 'gtrrc journal entry 1 line one\ngtrrc journal entry 1 line two'}, {sTargetTable: 'incident', aQueryFields: ['sys_id']}, {});
	_gtRecordWrite.doRecord({sys_id: sIncidentId, comments: 'gtrrc journal entry 2 line one\ngtrrc journal entry 2 line two'}, {sTargetTable: 'incident', aQueryFields: ['sys_id']}, {});
	
	// 14 PRIORITY 1: aDisplayValueTypes in value mode on a reference field returns the display_value/value object (regression guard for getInternalType)
	_gtATF.runATF('getData', /"manager":\{"display_value":"GTRRC Manager","value":"[a-f0-9]{32}"\}/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['manager'], aDisplayValueTypes: ['reference'] }); // reference type triggers object form

	// 15 aDisplayValueTypes that does NOT include the field's internal type leaves the raw sys_id value as a string
	_gtATF.runATF('getData', /"manager":"[a-f0-9]{32}"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['manager'], aDisplayValueTypes: ['date_time'] }); // type not listed keeps sys_id string

	// 16 bLegacyDisplayValue with aDisplayValueTypes writes a flat <field>_dv key instead of the object
	_gtATF.runATF('getData', /"manager_dv":"GTRRC Manager"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['manager'], aDisplayValueTypes: ['reference'], bLegacyDisplayValue: true }); // legacy postfix form

	// 17 custom legacy postfix is honoured
	_gtATF.runATF('getData', /"manager__disp":"GTRRC Manager"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['manager'], aDisplayValueTypes: ['reference'], bLegacyDisplayValue: true, sLegacyDisplayValuePostfix: '__disp' }); // custom postfix

	// 18 PRIORITY 2: oRelatedTables join produces a child array keyed under the related table name (employee has 2 role records)
	_gtATF.runATF('getData', /"sys_user_has_role":\[\{/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', aFields: ['role'] } } }); // child join array

	// 19 related table sReturnType reference keys the child result under the source field name
	_gtATF.runATF('getData', /"sys_id":\{/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', sReturnType: 'reference', aFields: ['role'] } } }); // reference keyed by source field

	// 20 related table hidden return type flattens children into a flat array under the table key
	_gtATF.runATF('getData', /"sys_user_has_role":\[\{"sys_id"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', sReturnType: 'hidden', bUniqueChildResultId: true, oRelatedTables: { sys_user_role: { sKeySourceField: 'role', sKeyTargetField: 'sys_id', aFields: ['sys_id', 'name'] } } } } }); // hidden flatten with unique ids

	// 21 iRelatedTablesMandatoryTarget keeps only top records meeting the mandatory related count (employee has roles so it is kept)
	_gtATF.runATF('getData', /"iNumberOfRecordsReturned":1/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], iRelatedTablesMandatoryTarget: 1, oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', bValidParentObject: true, aFields: ['role'] } } }); // mandatory related target met

	// 22 LABELS: bUseFieldLabel uses the human readable dictionary label as the key
	_gtATF.runATF('getData', /"User ID":"gtrrc.employee"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bUseFieldLabel: true }); // field label key

	// 23 bUseTableCamelCaseLabel converts the related table key to camel case
	_gtATF.runATF('getData', /"sysUserHasRole":\[/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bUseTableCamelCaseLabel: true, oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', aFields: ['role'] } } }); // camel case related table label

	// 24 bUseTablePascalCaseLabel converts the related table key to pascal case
	_gtATF.runATF('getData', /"SysUserHasRole":\[/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bUseTablePascalCaseLabel: true, oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', aFields: ['role'] } } }); // pascal case related table label

	// 25 sTableName overrides the related result key with an explicit label
	_gtATF.runATF('getData', /"roles":\[/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oRelatedTables: { sys_user_has_role: { sKeySourceField: 'sys_id', sKeyTargetField: 'user', sTableName: 'roles', aFields: ['role'] } } }); // explicit related table label

	// 26 sRefFieldConcatChar customises the join character for reference field keys (company populated on the fixture employee)
	_gtATF.runATF('getData', /"company\.name":"GTRRC Test Company"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], sRefFieldConcatChar: '.', oReferenceFields: { company: { aFields: ['name'] } } }); // custom concat char

	// 27 ORDERING: aOrderByDesc path runs and returns the fixture rows
	_gtATF.runATF('getData', /"user_name":"gtrrc/, { sTable: 'sys_user', sQuery: 'user_nameSTARTSWITHgtrrc.', aFields: ['user_name'], aOrderByDesc: ['user_name'], iMaxReturnCount: 1 }); // order by desc returns gtrrc.manager first

	// 28 aQueryParamsOrderByFields (request override) takes precedence over aOrderBy and still returns rows
	_gtATF.runATF('getData', /"user_name":"gtrrc.employee"/, { sTable: 'sys_user', sQuery: 'user_nameSTARTSWITHgtrrc.', aFields: ['user_name'], aOrderBy: ['sys_id'], aQueryParamsOrderByFields: ['user_name'], iMaxReturnCount: 1 }); // request order override (employee sorts before manager)

	// 29 PAGING: iRequestReturnOffset with iMaxReturnCount pages the window and still reports the full matched count (2 fixture users)
	_gtATF.runATF('getData', /"iNumberOfRecordsReturned":2/, { sTable: 'sys_user', sQuery: 'user_nameSTARTSWITHgtrrc.', aFields: ['user_name'], iMaxReturnCount: 1, iRequestReturnOffset: 1 }); // offset paging keeps full count

	// 30 iRequestMaxReturnCount overrides the configured iMaxReturnCount default and returns the data envelope
	_gtATF.runATF('getData', /"data":\[\{/, { sTable: 'sys_user', sQuery: 'user_nameSTARTSWITHgtrrc.', aFields: ['user_name'], iMaxReturnCount: 100, iRequestMaxReturnCount: 1 }); // request max overrides config

	// 31 GR FLAGS: bNoWorkflow read path still returns the record
	_gtATF.runATF('getData', /"user_name":"gtrrc.employee"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bNoWorkflow: true }); // no workflow read

	// 32 bUseGlideRecordSecure read path returns the record for an admin caller
	_gtATF.runATF('getData', /"user_name":"gtrrc.employee"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bUseGlideRecordSecure: true }); // GlideRecordSecure read

	// 33 bNoDomain read path returns the record
	_gtATF.runATF('getData', /"user_name":"gtrrc.employee"/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bNoDomain: true }); // no domain read

	// 34 ATTACHMENTS: bReturnAttachmentInfoArray adds the attachments key as an array form
	_gtATF.runATF('getData', /"attachments":\[/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], bReturnAttachmentInfoArray: true }); // attachment array form

	// 35 JOURNAL: oJournalFields reads the last comments journal entry into the comments key
	_gtATF.runATF('getData', /comments":"/, { sTable: 'incident', sQuery: 'sys_id=' + sIncidentId, aFields: ['short_description'], oJournalFields: { comments: { iNumber: 1 } } }); // journal field last entry

	// 36 oJournalFields with sReturnType array returns the journal entries as an array
	_gtATF.runATF('getData', /comments":\["/, { sTable: 'incident', sQuery: 'sys_id=' + sIncidentId, aFields: ['short_description'], oJournalFields: { comments: { iNumber: -1, sReturnType: 'array' } } }); // journal array form

	// 37 ATTRIBUTE PIVOT: oAttributeTable pivots matching rows onto the record under sFieldPrefix + name-field value (here a role assignment keyed by its role)
	_gtATF.runATF('getData', new RegExp('"attr_' + sRoleAId + '"'), { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oAttributeTable: { sBaseTableName: 'sys_user', sAttributeTableName: 'sys_user_has_role', sAttributeReferenceField: 'user', sAttributeNameField: 'role', sAttributeValueField: 'role', aCIAttributeNames: [sRoleAId, sRoleBId], sFieldPrefix: 'attr_' } }); // attribute pivot writes prefixed key

	// 38 oAttributeTable does nothing when the configured base table does not match the record base (no attr_ key, record still returned)
	_gtATF.runATF('getData', /"data":\[\{"user_name":"gtrrc.employee"\}\]/, { sTable: 'sys_user', sQuery: 'user_name=gtrrc.employee', aFields: ['user_name'], oAttributeTable: { sBaseTableName: 'cmdb', sAttributeTableName: 'sys_user_has_role', sAttributeReferenceField: 'user', sAttributeNameField: 'role', sAttributeValueField: 'role', aCIAttributeNames: [sRoleAId], sFieldPrefix: 'attr_' } }); // base table mismatch skips pivot, only user_name present

	return _gtATF.endATF();
})(outputs, steps, params, stepResult, assertEqual);
